<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();mb_require_any_permission($pdo,['view_hr','manage_employees']);require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$can=current_user_can($pdo,'manage_employees');$edit=null;if($_SERVER['REQUEST_METHOD']==='POST'&&$can){try{csrf_verify();$a=$_POST['action']??'';if($a==='save'){$id=(int)($_POST['id']??0);$data=[trim($_POST['employee_code']??''),trim($_POST['full_name']??''),trim($_POST['employee_type']??''),trim($_POST['job_title']??''),trim($_POST['department']??''),trim($_POST['phone']??''),trim($_POST['email']??''),(float)($_POST['daily_rate']??0),trim($_POST['status']??'active'),trim($_POST['notes']??'')];if($data[1]==='')throw new RuntimeException('Full name required.');if($id){$pdo->prepare("UPDATE mb_employees SET employee_code=?,full_name=?,employee_type=?,job_title=?,department=?,phone=?,email=?,daily_rate=?,status=?,notes=? WHERE id=?")->execute([...$data,$id]);mb_set_success('Employee updated.');}else{$pdo->prepare("INSERT INTO mb_employees (employee_code,full_name,employee_type,job_title,department,phone,email,daily_rate,status,notes) VALUES (?,?,?,?,?,?,?,?,?,?)")->execute($data);mb_set_success('Employee created.');}}elseif($a==='delete'){$pdo->prepare("DELETE FROM mb_employees WHERE id=?")->execute([(int)$_POST['id']]);mb_set_success('Employee deleted.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('index.php');}if(isset($_GET['edit'])){$st=$pdo->prepare("SELECT * FROM mb_employees WHERE id=?");$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(PDO::FETCH_ASSOC);} $rows=$pdo->query("SELECT * FROM mb_employees ORDER BY status ASC, full_name ASC")->fetchAll(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Employees','Employees');?>
<?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="mb-card"><div class="mb-card-header"><strong>Admin and project employees</strong><?php if($can):?><button class="btn btn-primary" data-mb-open-modal="empModal">New Employee</button><?php endif;?></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>Code</th><th>Name</th><th>Type</th><th>Title</th><th>Department</th><th>Contact</th><th>Daily Rate</th><th>Status</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=htmlspecialchars($r['employee_code'])?></td><td><strong><?=htmlspecialchars($r['full_name'])?></strong><div class="small text-muted"><?=htmlspecialchars($r['email'])?></div></td><td><?=htmlspecialchars($r['employee_type'])?></td><td><?=htmlspecialchars($r['job_title'])?></td><td><?=htmlspecialchars($r['department'])?></td><td><?=htmlspecialchars($r['phone'])?></td><td>₱<?=mb_money($r['daily_rate'])?></td><td><span class="mb-badge <?=$r['status']==='active'?'success':'danger'?>"><?=htmlspecialchars($r['status'])?></span></td><td class="mb-actions"><?php if($can):?><a class="btn btn-sm btn-outline-primary" href="?edit=<?=(int)$r['id']?>">Edit</a><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete employee?">Delete</button></form><?php endif;?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="9" class="text-center text-muted py-4">No employees yet.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="empModal"><div class="modal-dialog modal-lg"><form method="post" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><div class="modal-header"><h5 class="modal-title"><?=$edit?'Edit':'New'?> Employee</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="mb-form-grid"><label>Code<input class="form-control" name="employee_code" value="<?=htmlspecialchars($edit['employee_code']??'')?>"></label><label>Full Name<input required class="form-control" name="full_name" value="<?=htmlspecialchars($edit['full_name']??'')?>"></label><label>Type<input class="form-control" name="employee_type" value="<?=htmlspecialchars($edit['employee_type']??'')?>"></label><label>Job Title<input class="form-control" name="job_title" value="<?=htmlspecialchars($edit['job_title']??'')?>"></label><label>Department<input class="form-control" name="department" value="<?=htmlspecialchars($edit['department']??'')?>"></label><label>Phone<input class="form-control" name="phone" value="<?=htmlspecialchars($edit['phone']??'')?>"></label><label>Email<input class="form-control" name="email" value="<?=htmlspecialchars($edit['email']??'')?>"></label><label>Daily Rate<input class="form-control" type="number" step="0.01" name="daily_rate" value="<?=htmlspecialchars($edit['daily_rate']??'0')?>"></label><label>Status<input class="form-control" name="status" value="<?=htmlspecialchars($edit['status']??'active')?>"></label><label class="full">Notes<textarea class="form-control" name="notes"><?=htmlspecialchars($edit['notes']??'')?></textarea></label></div></div><div class="modal-footer"><button class="btn btn-primary">Save Employee</button></div></form></div></div><script><?php if($edit):?>new bootstrap.Modal(document.getElementById('empModal')).show();<?php endif;?></script><?php mb_workspace_footer();?>